import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import BookingForm from '../components/BookingForm';
import BookingSummary from '../components/BookingSummary';
import Modal from '../components/Modal';

const Booking = () => {
  const { bikeId } = useParams();
  const navigate = useNavigate();

  const [selectedBike, setSelectedBike] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [bookingDetails, setBookingDetails] = useState(null);

  const [formData, setFormData] = useState({
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    customer_address: '',
    customer_license: '',
    pickup_date: '',
    return_date: '',
    pickup_location: '',
    return_location: '',
    special_requests: ''
  });

  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (bikeId) fetchBikeDetails();
  }, [bikeId]);

  useEffect(() => {
    validateForm();
  }, [formData]);

  const fetchBikeDetails = async () => {
    try {
      const response = await fetch(`http://localhost:5002/api/bikes/${bikeId}`);
      const result = await response.json();
      if (result.success) {
        setSelectedBike(result.data);
      } else {
        navigate('/fleet');
      }
    } catch (error) {
      console.error('Error fetching bike details:', error);
      navigate('/fleet');
    } finally {
      setLoading(false);
    }
  };

  const calculateTotalAmount = () => {
    if (!selectedBike || !formData.pickup_date || !formData.return_date) return 0;
    const pickup = new Date(formData.pickup_date);
    const returnDate = new Date(formData.return_date);
    const rentalDays = Math.ceil((returnDate - pickup) / (1000 * 60 * 60 * 24)) || 1;
    const baseAmount = selectedBike.price * rentalDays;
    const insurance = baseAmount * 0.10;
    const tax = (baseAmount + insurance) * 0.08;
    return baseAmount + insurance + tax;
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.customer_name.trim()) newErrors.customer_name = 'Name is required';
    if (!formData.customer_email.trim()) newErrors.customer_email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(formData.customer_email)) newErrors.customer_email = 'Email is invalid';
    if (!formData.customer_phone.trim()) newErrors.customer_phone = 'Phone number is required';
    if (!formData.customer_address.trim()) newErrors.customer_address = 'Address is required';
    if (!formData.customer_license.trim()) newErrors.customer_license = 'License number is required';
    if (!formData.pickup_date) newErrors.pickup_date = 'Pickup date is required';
    else if (new Date(formData.pickup_date) < new Date().setHours(0, 0, 0, 0)) newErrors.pickup_date = 'Pickup date cannot be in the past';
    if (!formData.return_date) newErrors.return_date = 'Return date is required';
    else if (formData.pickup_date && new Date(formData.return_date) <= new Date(formData.pickup_date)) newErrors.return_date = 'Return date must be after pickup date';
    if (!formData.pickup_location) newErrors.pickup_location = 'Pickup location is required';
    if (!formData.return_location) newErrors.return_location = 'Return location is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;
    setIsSubmitting(true);
    try {
      const totalAmount = calculateTotalAmount();
      const bookingData = { bike_id: selectedBike.id, ...formData, total_amount: totalAmount };
      const response = await fetch('http://localhost:5002/api/bookings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bookingData),
      });
      const result = await response.json();
      if (result.success) {
        setBookingDetails(result.data);
        setShowSuccessModal(true);
        setFormData({
          customer_name: '', customer_email: '', customer_phone: '', customer_address: '', customer_license: '',
          pickup_date: '', return_date: '', pickup_location: '', return_location: '', special_requests: ''
        });
      } else {
        alert(result.message || 'Booking failed. Please try again.');
      }
    } catch (error) {
      console.error('Error creating booking:', error);
      alert('Booking failed. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) {
    return <div className="loading"><div className="spinner"></div></div>;
  }

  return (
    <div>
      <div className="section-title">
        <h2>Book Your Bike</h2>
        <p>Fill in the customer details to create a new booking</p>
      </div>

      <div className="grid-2" style={{ gap: '1.5rem', alignItems: 'start' }}>
        <div className="card">
          <div className="card-header">
            <h3>Booking Information</h3>
          </div>
          <div className="card-body">
            <BookingForm
              formData={formData}
              onChange={handleInputChange}
              errors={errors}
              onSubmit={handleSubmit}
              isSubmitting={isSubmitting}
              selectedBike={selectedBike}
            />
          </div>
        </div>

        <div>
          <BookingSummary
            selectedBike={selectedBike}
            formData={formData}
            totalAmount={calculateTotalAmount()}
          />
        </div>
      </div>

      {/* Success Modal */}
      <Modal
        isOpen={showSuccessModal}
        onClose={() => setShowSuccessModal(false)}
        title="Booking Confirmed!"
      >
        {bookingDetails && (
          <div>
            <div className="form-success-msg">
              Your booking has been confirmed successfully!
            </div>

            <div style={{ marginBottom: '1.25rem' }}>
              <h4 style={{ marginBottom: '0.75rem', fontSize: '0.9rem', fontWeight: 600 }}>Booking Details:</h4>
              <div className="summary-item">
                <span>Booking ID:</span>
                <strong>{bookingDetails.booking_id}</strong>
              </div>
              <div className="summary-item">
                <span>Bike:</span>
                <span>{bookingDetails.bike_name}</span>
              </div>
              <div className="summary-item">
                <span>Total Amount:</span>
                <span>₹{parseFloat(bookingDetails.total_amount).toFixed(2)}</span>
              </div>
              <div className="summary-item">
                <span>Status:</span>
                <span className="badge badge--warning"><span className="badge-dot"></span>{bookingDetails.status}</span>
              </div>
            </div>

            <p style={{ marginBottom: '1.25rem', fontSize: '0.8rem', color: 'var(--text-muted)' }}>
              Confirmation email sent to {bookingDetails.customer_email}.
              Please bring your driving license and ID proof when you come to pick up the bike.
            </p>

            <div style={{ display: 'flex', gap: '0.75rem' }}>
              <button className="btn btn-primary" onClick={() => navigate('/bookings')} style={{ flex: 1 }}>
                View Bookings
              </button>
              <button className="btn btn-secondary" onClick={() => setShowSuccessModal(false)} style={{ flex: 1 }}>
                Close
              </button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default Booking;
